diagram.mermaid:
classDiagram
  class EmbodiedProxy {
    +int energy_0_10
    +int fatigue_0_10
    +string environment
    +string emoji
    +timestamp updated_at
  }
  class Human {
    +update_proxy()
  }
  class Agent {
    +read_proxy_on_prompt()
    +shape_response()
  }
  Human --> EmbodiedProxy : writes
  Agent --> EmbodiedProxy : reads
